                    ans: '<math xmlns="http://www.w3.org/1998/Math/MathML"><mfenced><mi mathvariant="normal">a</mi></mfenced><mo>\u2212</mo><mfenced><mi>ii</mi></mfenced><mo>,</mo><mfenced><mi mathvariant="normal">b</mi></mfenced><mo>\u2212</mo><mfenced><mi mathvariant="normal">i</mi></mfenced><mo>,</mo><mfenced><mi mathvariant="normal">c</mi></mfenced><mo>\u2212</mo><mfenced><mi>iii</mi></mfenced><mo>,</mo><mfenced><mi mathvariant="normal">d</mi></mfenced><mo>\u2212</mo><mfenced><mi>iv</mi></mfenced></math>',
                    correct: "ktFUX",
