                    ans: '<img src="https://cdn-question-pool.getmarks.app/pyq_book_2024/a63d2328-aeac-46c8-a2e7-fa2c708b81b4-image.png" style="width: 344px; height: 137px;"/>',
                    correct: "XC0q0",
