                    ans: '<math><mi mathvariant="normal">d</mi><mi mathvariant="normal">\u00a0</mi><mi mathvariant="normal">a</mi><mi mathvariant="normal">\u00a0</mi><mi mathvariant="normal">b</mi><mi mathvariant="normal">\u00a0</mi><mi mathvariant="normal">c</mi></math>',
                    correct: "0DOhJ",
