const navList = document.getElementById("nav-list"),
    contentArea = document.getElementById("content-area"),
    chapTitle = document.getElementById("chap-title");
function init() {
    for (const [e, t] of Object.entries(RAW_DATA)) {
        const n = document.createElement("div");
        n.className = "subject-group collapsed";
        
        const header = document.createElement("div");
        header.className = "subject-title";
        header.innerHTML = `<span>${e}</span><svg class="chevron" xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><polyline points="6 9 12 15 18 9"></polyline></svg>`;
        
        const listContainer = document.createElement("div");
        listContainer.className = "chapter-list-container";
        
        header.onclick = () => {
            n.classList.toggle("collapsed");
        };
        
        n.appendChild(header);
        
        t.forEach((t, a) => {
            const c = document.createElement("div");
            c.className = "chapter-item";
            c.textContent = t.name + ` (${t.qs.length})`;
            c.onclick = () => loadChapter(e, a, c);
            listContainer.appendChild(c);
        });
        
        n.appendChild(listContainer);
        navList.appendChild(n);
    }
}
function loadChapter(e, t, n) {
    document.querySelectorAll(".chapter-item").forEach((e) => e.classList.remove("active")),
        n.classList.add("active");
    const a = RAW_DATA[e][t];
    (chapTitle.textContent = a.name),
        (contentArea.innerHTML = ""),
        a.qs.forEach((e, t) => {
            const n = document.createElement("div");
            n.className = "card";
            let a = "";
            e.opts && e.opts.length > 0
                ? e.opts.forEach((t) => {
                      a += `<label class="opt" id="opt-${e.id}-${t.id}"><input type="radio" name="q-${e.id}" value="${t.id}"><div>${t.text}</div></label>`;
                  })
                : (a =
                      '<input type="text" placeholder="Answer" style="padding:10px; width:200px; border:1px solid #ccc; border-radius:4px;">'),
                (n.innerHTML = `<div class="q-meta">Q${t + 1} • ${e.type}</div><div>${e.html}</div><div style="margin:15px 0">${a}</div><button class="btn-sol" onclick="reveal('${e.id}')">View Solution</button><div id="sol-${e.id}" class="sol-box"><div style="font-weight:bold; color:#28a745; margin-bottom:5px">SOLUTION:</div>${e.sol}<div style="margin-top:10px; border-top:1px solid #ddd; padding-top:5px; font-weight:bold;">Answer: ${e.ans}</div></div>`),
                contentArea.appendChild(n);
        }),
        window.MathJax && MathJax.typeset();
}
window.reveal = function (e) {
    let t = null;
    for (let n in RAW_DATA) {
        for (let a of RAW_DATA[n]) {
            let c = a.qs.find((t) => t.id === e);
            if (c) {
                t = c;
                break;
            }
        }
        if (t) break;
    }
    document.getElementById("sol-" + e).style.display = "block";
    if (t && t.opts.length > 0) {
        const n = document.querySelector(`input[name="q-${e}"]:checked`)?.value;
        t.correct && document.getElementById(`opt-${e}-${t.correct}`).classList.add("correct"),
            n && n !== t.correct && document.getElementById(`opt-${e}-${n}`).classList.add("wrong");
    }
};
init();
